import Head from 'next/head'
import { useState, useEffect } from 'react'
import wordsData from '../data/words.json'
import styles from '../styles/Home.module.css'

export default function Home() {
  const [currentIndex, setCurrentIndex] = useState(0)
  const [showAnswer, setShowAnswer] = useState(false)
  const [isLoaded, setIsLoaded] = useState(false)

  // Load progress from localStorage on mount
  useEffect(() => {
    const savedIndex = localStorage.getItem('wordcard-index')
    if (savedIndex !== null) {
      const index = parseInt(savedIndex, 10)
      if (index >= 0 && index < wordsData.length) {
        setCurrentIndex(index)
      }
    }
    setIsLoaded(true)
  }, [])

  // Save progress to localStorage
  useEffect(() => {
    if (isLoaded) {
      localStorage.setItem('wordcard-index', currentIndex.toString())
    }
  }, [currentIndex, isLoaded])

  const nextWord = () => {
    setCurrentIndex((currentIndex + 1) % wordsData.length)
    setShowAnswer(false)
  }

  const prevWord = () => {
    setCurrentIndex((currentIndex - 1 + wordsData.length) % wordsData.length)
    setShowAnswer(false)
  }

  const toggleFlip = () => setShowAnswer(!showAnswer)

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault()
      toggleFlip()
    }
  }

  if (!wordsData || wordsData.length === 0) {
    return <div className={styles.container}>暂无单词数据</div>
  }

  const word = wordsData[currentIndex]

  // Prevent hydration mismatch by not rendering the dynamic part until loaded
  if (!isLoaded) return null

  return (
    <div className={styles.container}>
      <Head>
        <title>师傅的购物单词本</title>
      </Head>
      
      <h1 className={styles.title}>🛒 购物单词本</h1>
      
      <div 
        role="button"
        tabIndex={0}
        aria-label={`单词卡片: ${word.japanese}. 点击或按空格键翻转查看释义`}
        onKeyDown={handleKeyDown}
        onClick={toggleFlip}
        className={`${styles.card} ${showAnswer ? styles.cardFlipped : ''}`}
      >
        <h2 className={styles.wordJapanese}>{word.japanese}</h2>
        <p className={styles.wordKana}>{word.kana}</p>
        
        {showAnswer ? (
          <div className={styles.answerArea}>
            <p className={styles.wordChinese}>{word.chinese}</p>
            <p className={styles.wordEnglish}>{word.english}</p>
            <small className={styles.wordSource}>来源: {word.source}</small>
          </div>
        ) : (
          <p className={styles.hint}>点击或按空格查看释义</p>
        )}
      </div>
      
      <div className={styles.buttonGroup}>
        <button 
          onClick={prevWord}
          aria-label="上一个单词"
          className={`${styles.button} ${styles.buttonSecondary}`}
        >
          ← 上一个
        </button>

        <button 
          onClick={nextWord}
          aria-label="下一个单词"
          className={`${styles.button} ${styles.buttonPrimary}`}
        >
          下一个 →
        </button>
      </div>

      <div className={styles.progress}>
        进度: {currentIndex + 1} / {wordsData.length}
      </div>
      
      <footer className={styles.footer}>
        <p>词库自动同步自师傅的购物小票</p>
      </footer>
    </div>
  )
}
